import{_ as a,o as t,c as i,a3 as o}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse(`{"title":"AI Overview","description":"Learn about Notely's modular, local-first AI platform.","frontmatter":{"title":"AI Overview","description":"Learn about Notely's modular, local-first AI platform.","keywords":"ai, local llm, openai, huggingface, vector database, knowledge graph","category":"AI"},"headers":[],"relativePath":"ai/index.md","filePath":"ai/index.md","lastUpdated":1784574024000}`),s={name:"ai/index.md"};function r(l,e,n,d,c,u){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="ai-subsystem-overview" tabindex="-1">AI Subsystem Overview <a class="header-anchor" href="#ai-subsystem-overview" aria-label="Permalink to &quot;AI Subsystem Overview&quot;">​</a></h1><p>Notely features a modular, local-first AI platform designed around private data control. Markdown files remain the absolute source of truth, parsed and indexed into offline-first databases to fuel assistant reasoning.</p><hr><h2 id="capabilities-at-a-glance" tabindex="-1">Capabilities at a Glance <a class="header-anchor" href="#capabilities-at-a-glance" aria-label="Permalink to &quot;Capabilities at a Glance&quot;">​</a></h2><h3 id="_1-global-workspace-chat-note-assistant" tabindex="-1">1. Global Workspace Chat &amp; Note Assistant <a class="header-anchor" href="#_1-global-workspace-chat-note-assistant" aria-label="Permalink to &quot;1. Global Workspace Chat &amp; Note Assistant&quot;">​</a></h3><ul><li>Chat inside individual notes or launch <strong>Global Chat</strong> from the left panel sidebar on the landing page to query across the entire workspace.</li><li>View referred notes chips under assistant message bubbles so you always know where facts were sourced.</li></ul><h3 id="_2-sqlite-knowledge-graph" tabindex="-1">2. SQLite Knowledge Graph <a class="header-anchor" href="#_2-sqlite-knowledge-graph" aria-label="Permalink to &quot;2. SQLite Knowledge Graph&quot;">​</a></h3><ul><li>Outbound relations, tags, and CTE traversals mapped into <code>ai-graph.db</code>.</li><li>Visualized interactively in the sidebar sidebar.</li></ul><h3 id="_3-local-embedding-indexer" tabindex="-1">3. Local Embedding Indexer <a class="header-anchor" href="#_3-local-embedding-indexer" aria-label="Permalink to &quot;3. Local Embedding Indexer&quot;">​</a></h3><ul><li>High-performance <code>ai-embeddings.db</code> storing note chunk vectors.</li><li>Runs entirely offline using a local ONNX runtime for <code>BGE-small-en-v1.5</code> embeddings, or falls back to HuggingFace APIs.</li><li>Background Index Worker priority queues processing note changes debounced.</li></ul><h3 id="_4-custom-persona-registry" tabindex="-1">4. Custom Persona Registry <a class="header-anchor" href="#_4-custom-persona-registry" aria-label="Permalink to &quot;4. Custom Persona Registry&quot;">​</a></h3><ul><li>Customize instructions, descriptions, and preset avatar icons (🤖, 💻, 🧠, etc.).</li><li>Import and export personas as Markdown templates.</li></ul><h3 id="_5-diagnostics-trace-logs" tabindex="-1">5. Diagnostics &amp; Trace Logs <a class="header-anchor" href="#_5-diagnostics-trace-logs" aria-label="Permalink to &quot;5. Diagnostics &amp; Trace Logs&quot;">​</a></h3><ul><li>Professional <strong>AI Health</strong> panel to verify subsystem initialization.</li><li>Full trace logs displaying exact tool calls, arguments, and return values for all queries.</li></ul>',14)])])}const p=a(s,[["render",r]]);export{g as __pageData,p as default};
